/**
 * Crea el Google Form del Kit “Valor Oculto” COMPLETO y lo vincula al Sheet Master.
 * - SHEET_ID ya está configurado con tu archivo: 1Ton2IQSVdgqNU7Cg2OIbkBxNlstzB2XIsTZOQvpLJHk
 * - Renombra la hoja de respuestas a "Respuestas" para alinearse con el Master.
 */

function createValorOcultoForm() {
  var PASSWORD = 'VALOROCULTO'; // cámbiala si lo deseas
  var SHEET_ID = '1Ton2IQSVdgqNU7Cg2OIbkBxNlstzB2XIsTZOQvpLJHk';

  var form = FormApp.create('Kit “Valor Oculto” — Captura de datos');
  form.setIsQuiz(false);
  form.setProgressBar(true);
  form.setCollectEmail(false);
  form.setLimitOneResponsePerUser(false);
  form.setConfirmationMessage('¡Listo! Te enviaremos tu 1-pager con la estrategia recomendada y una explicación breve.');

  // Vincular al Sheet Master y renombrar la hoja de respuestas a "Respuestas"
  form.setDestination(FormApp.DestinationType.SPREADSHEET, SHEET_ID);
  ensureResponsesSheetNamed_(SHEET_ID, 'Respuestas');

  // ===== Sección A — Acceso
  form.addSectionHeaderItem().setTitle('Acceso');
  var pass = form.addTextItem()
    .setTitle('clave_acceso')
    .setHelpText('Ingresa la clave de acceso.')
    .setRequired(true);
  pass.setValidation(
    FormApp.createTextValidation()
      .requireTextMatchesPattern('^' + PASSWORD.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&') + '$')
      .setHelpText('La clave no coincide.')
      .build()
  );

  // Salto a Datos de la propiedad
  form.addPageBreakItem().setTitle('Datos de la propiedad');

  // ===== Sección B — Datos de la propiedad
  var tipoProp = form.addMultipleChoiceItem()
    .setTitle('tipo_propiedad')
    .setRequired(true);
  tipoProp.setChoices([
    tipoProp.createChoice('Casa'),
    tipoProp.createChoice('Departamento'),
    tipoProp.createChoice('Terreno'),
    tipoProp.createChoice('Otro (especifica en comentarios)')
  ]);

  form.addTextItem()
    .setTitle('ubicacion')
    .setHelpText('Colonia / Municipio / Estado')
    .setRequired(true);

  var tipoCiudad = form.addListItem()
    .setTitle('tipo_ciudad (A/B/C/D)')
    .setHelpText('A=Metrópoli top (CDMX/MTY/GDL) · B=Capital/Regional · C=Mediana/Satélite · D=Local/Periférica')
    .setRequired(true);
  tipoCiudad.setChoices([
    tipoCiudad.createChoice('A'),
    tipoCiudad.createChoice('B'),
    tipoCiudad.createChoice('C'),
    tipoCiudad.createChoice('D')
  ]);

  var arquetipo = form.addListItem()
    .setTitle('arquetipo (CHT/CBD/FRA/CMS/CLI/PRN)')
    .setHelpText('CHT=Centro histórico · CBD=Corredor negocios · FRA=Residencial 1er anillo alto · CMS=Centro municipal · CLI=Corredor logístico · PRN=Periferia residencial nueva')
    .setRequired(true);
  arquetipo.setChoices([
    arquetipo.createChoice('CHT'),
    arquetipo.createChoice('CBD'),
    arquetipo.createChoice('FRA'),
    arquetipo.createChoice('CMS'),
    arquetipo.createChoice('CLI'),
    arquetipo.createChoice('PRN')
  ]);

  var zona = form.addListItem()
    .setTitle('zona (opcional)')
    .setHelpText('Si no estás seguro, elige "No sé".');
  zona.setChoices([
    zona.createChoice('Centro'),
    zona.createChoice('Intermedia'),
    zona.createChoice('Periférica'),
    zona.createChoice('No sé')
  ]);

  var valor = form.addTextItem()
    .setTitle('valor_mercado_hoy_MXN')
    .setHelpText('Si tienes un rango, usa el valor medio.')
    .setRequired(true);
  valor.setValidation(
    FormApp.createTextValidation()
      .requireNumberGreaterThan(0)
      .setHelpText('Ingresa un número mayor a 0')
      .build()
  );

  var horizonte = form.addMultipleChoiceItem()
    .setTitle('horizonte_meses')
    .setRequired(true);
  horizonte.setChoices([
    horizonte.createChoice('12'),
    horizonte.createChoice('24'),
    horizonte.createChoice('36')
  ]);

  // Pregunta de branching: ¿construir?
  var construir = form.addMultipleChoiceItem()
    .setTitle('planea_construir (Si/No)')
    .setRequired(true);

  // ===== PageBreak y Sección C — Construcción
  var pbConstruccion = form.addPageBreakItem().setTitle('Construcción');

  var m2 = form.addTextItem()
    .setTitle('m2_construccion')
    .setHelpText('Estimado. Validaremos normatividad nosotros.')
    .setRequired(true);
  m2.setValidation(
    FormApp.createTextValidation()
      .requireNumberGreaterThan(0)
      .setHelpText('Ingresa un número mayor a 0')
      .build()
  );

  var costoM2 = form.addTextItem()
    .setTitle('costo_m2_MXN')
    .setHelpText('Opcional. Si lo dejas vacío, usaremos el valor prudente por tipo/arquetipo.');

  var mesesObra = form.addMultipleChoiceItem()
    .setTitle('meses_obra')
    .setRequired(true);
  mesesObra.setChoices([
    mesesObra.createChoice('4'),
    mesesObra.createChoice('5'),
    mesesObra.createChoice('6'),
    mesesObra.createChoice('7'),
    mesesObra.createChoice('8'),
    mesesObra.createChoice('9+')
  ]);

  var destino = form.addMultipleChoiceItem()
    .setTitle('destino_post (Rentar/Vender/No se)')
    .setRequired(true);
  destino.setChoices([
    destino.createChoice('Rentar'),
    destino.createChoice('Vender'),
    destino.createChoice('No se')
  ]);

  form.addTextItem().setTitle('renta_post_MXN').setHelpText('Opcional: si no sabes, lo estimamos por tipo/arquetipo.');
  form.addTextItem().setTitle('precio_venta_post_MXN').setHelpText('Opcional: si no sabes, usamos comparables prudentes.');
  form.addTextItem().setTitle('costos_post_MXN').setHelpText('Opcional: condominio, mantenimiento, seguros, administración.');

  // ===== PageBreak y Sección D — Ingresos/Gastos actuales
  var pbIngresos = form.addPageBreakItem().setTitle('Ingresos/Gastos actuales (opcional)');

  // Branching de construir
  construir.setChoices([
    construir.createChoice('Si', pbConstruccion),
    construir.createChoice('No', pbIngresos)
  ]);

  form.addTextItem().setTitle('renta_mensual_actual_MXN').setHelpText('Opcional');
  form.addTextItem().setTitle('ocupacion_esperada_(0-1_o_% )').setHelpText('Opcional. 0.85 o 85%');
  form.addTextItem().setTitle('gasto_mensual_propiedad_MXN').setHelpText('Opcional. Condominio, mantenimiento, seguro, predial prorrateado.');

  var mesesVta = form.addMultipleChoiceItem().setTitle('meses_para_vender_hoy');
  mesesVta.setChoices([
    mesesVta.createChoice('2'),
    mesesVta.createChoice('3'),
    mesesVta.createChoice('4'),
    mesesVta.createChoice('5'),
    mesesVta.createChoice('6'),
    mesesVta.createChoice('7+')
  ]);

  var pctVenta = form.addMultipleChoiceItem().setTitle('pct_costos_venta (ej. 6%)');
  pctVenta.setChoices([
    pctVenta.createChoice('4%'),
    pctVenta.createChoice('5%'),
    pctVenta.createChoice('6%'),
    pctVenta.createChoice('7%'),
    pctVenta.createChoice('8%'),
    pctVenta.createChoice('No se')
  ]);

  // ===== PageBreak y Sección E — Semáforo de riesgo (9 Sí/No)
  form.addPageBreakItem().setTitle('Semáforo de riesgo');

  addSiNo_(form, 'risk_legal', 'Estatus legal incierto (ejido, posesión, juicio)', true);
  addSiNo_(form, 'risk_servicios', 'Conexión/servicios costosos o inciertos (agua/luz/drenaje)', false);
  addSiNo_(form, 'risk_mercado', 'Mercado con alto inventario / absorción lenta', false);
  addSiNo_(form, 'risk_seguridad', 'Inseguridad o percepción de riesgo en la zona', false);
  addSiNo_(form, 'risk_accesos', 'Accesos o transporte deficientes', false);
  addSiNo_(form, 'risk_fisicos', 'Riesgos físicos (inundación, falla geológica, rellenos)', false);
  addSiNo_(form, 'risk_condominio', 'Condómino/reglamento complicado', false);
  addSiNo_(form, 'risk_obra_publica', 'Obra pública incierta/aleatoria', false);
  addSiNo_(form, 'risk_competencia', 'Competencia fuerte (precio/calidad superior)', false);

  // ===== PageBreak y Sección F — Contacto y entrega
  form.addPageBreakItem().setTitle('Contacto y entrega');
  form.addTextItem().setTitle('nombre').setRequired(true);
  var email = form.addTextItem().setTitle('email').setRequired(true);
  email.setValidation(FormApp.createTextValidation().requireTextIsEmail().setHelpText('Ingresa un correo válido').build());
  form.addTextItem().setTitle('whatsapp').setHelpText('Opcional. Con lada, ej. +52...');

  form.addCheckboxItem()
    .setTitle('Acepto la nota: Entiendo que este resultado no es asesoría personalizada y depende de mis datos y del mercado.')
    .setRequired(true);

  Logger.log('Form URL (para compartir): ' + form.getPublishedUrl());
  Logger.log('Edit URL (para editar): ' + form.getEditUrl());
}

/** Helper: pregunta Sí/No (MultipleChoice) */
function addSiNo_(form, title, help, required) {
  var item = form.addMultipleChoiceItem().setTitle(title).setHelpText(help || '');
  item.setChoices([ item.createChoice('Si'), item.createChoice('No') ]).setRequired(!!required);
  return item;
}

/** Asegura que la hoja de respuestas del Form en el Spreadsheet se llame desiredName. */
function ensureResponsesSheetNamed_(spreadsheetId, desiredName) {
  var ss = SpreadsheetApp.openById(spreadsheetId);

  // Espera breve por si Forms tarda en crear la hoja
  for (var t = 0; t < 10; t++) {
    var respSheet = findResponsesSheet_(ss);
    if (respSheet) {
      var existing = ss.getSheetByName(desiredName);
      if (existing && existing.getSheetId() !== respSheet.getSheetId()) {
        existing.setName(desiredName + ' (old)');
      }
      respSheet.setName(desiredName);
      return;
    }
    Utilities.sleep(300);
  }
}

/** Detecta la hoja auto-creada por Forms en español o inglés. */
function findResponsesSheet_(ss) {
  var rgx = /^(Form Responses \d+|Respuestas de formulario \d+)$/i;
  var sheets = ss.getSheets();
  for (var i = 0; i < sheets.length; i++) {
    if (rgx.test(sheets[i].getName())) return sheets[i];
  }
  return null;
}
